import sqlite3
from typing import Optional

def authenticate_user(username: str, password: str) -> Optional[dict]:
    """
    Authenticate user against legacy database
    Returns user record if authentication successful, None otherwise
    """
    try:
        # Connect to legacy database
        conn = sqlite3.connect('legacy_database.db')
        cursor = conn.cursor()
        
        # Use parameterized query to prevent SQL injection
        query = "SELECT * FROM users WHERE username = ? AND password = ?"
        cursor.execute(query, (username, password))
        
        result = cursor.fetchone()
        
        if result:
            # Convert to dictionary for easier handling
            columns = [description[0] for description in cursor.description]
            user_record = dict(zip(columns, result))
            return user_record
        else:
            return None
            
    except sqlite3.Error as e:
        print(f"Database error: {e}")
        return None
    finally:
        if conn:
            conn.close()

# Example usage
if __name__ == "__main__":
    user = authenticate_user("john_doe", "secure_password")
    if user:
        print("Login successful")
        print(user)
    else:
        print("Login failed")